#!/usr/bin/env python3
# scripts/validate-log-access-policy.py
# Run in CI: fails if any role gains read access to audit-logs
# without explicit security-team approval tag.

import sys
import yaml
from pathlib import Path

AUDIT_STORES = {"audit-logs", "loki:audit-logs", "cloudwatch:audit"}
ALLOWED_AUDIT_ROLES = {"security", "compliance", "audit-bot", "break-glass"}

def load_policy(path: str) -> dict:
    return yaml.safe_load(Path(path).read_text())

def check_policy(policy: dict) -> list[str]:
    errors = []
    for binding in policy.get("roleBindings", []):
        role = binding["role"]
        for store in binding.get("canRead", []):
            if store in AUDIT_STORES and role not in ALLOWED_AUDIT_ROLES:
                errors.append(
                    f"Role '{role}' has read access to '{store}' — "
                    f"only {ALLOWED_AUDIT_ROLES} may access audit stores."
                )
    return errors

if __name__ == "__main__":
    policy_path = sys.argv[1] if len(sys.argv) > 1 else "config/log-access-policy.yaml"
    policy = load_policy(policy_path)
    errors = check_policy(policy)
    if errors:
        for e in errors:
            print(f"ERROR: {e}", file=sys.stderr)
        sys.exit(1)
    print(f"OK: log-access-policy.yaml passes {len(policy.get('roleBindings', []))} binding checks")
    sys.exit(0)
